@dataclass
class Address:
    street: str
    city: str
    state: str
    zip_code: str

    def get_full_address(self) -> str:
        return f"{self.street}, {self.city}, {self.state} {self.zip_code}"

@dataclass
class User:
    name: str
    email: str
    address: Address

class PricingStrategy(ABC):
    @abstractmethod
    def calculate_discount(self, product) -> Decimal: ...

class PremiumPricing(PricingStrategy):
    def calculate_discount(self, product) -> Decimal:
        return Decimal("0.1")

STRATEGIES = {"premium": PremiumPricing(), "regular": RegularPricing()}
strategy = STRATEGIES.get(customer_type, RegularPricing())

class ShippingConfig:
    FREE_SHIPPING_THRESHOLD = Decimal("100.00")
    STANDARD_SHIPPING_COST = Decimal("9.99")

if order.total >= ShippingConfig.FREE_SHIPPING_THRESHOLD:
    order.shipping = Decimal("0")
